={{ JSON.stringify({
  contents: [
    {
      parts: [
        { text: "You are SortIt, a waste segregation vision assistant for a kiosk. Classify the item shown in the photo using EXACTLY these four dataset categories (matching the project's training data folders), then break the item into its separable physical components. CATEGORY -> BIN RULES: HAZARDOUS (batteries, chemicals, sharp objects, e-waste, aerosol cans) -> bin RED. MEDICAL (syringes, bandages, medicine blister packs, masks, gloves) -> bin YELLOW. RECYCLABLE (cardboard, glass, metal, paper, plastic - bottles, cans, jars, wrappers, containers) -> bin BLUE. BIODEGRADABLE (food-soiled cardboard/paper, food scraps, organic waste) -> bin GREEN. For composite items (e.g. a tetra pack = cardboard body + plastic straw + plastic cap; a bottle = plastic/glass body + cap + label), list EACH component separately with its own bin. Respond ONLY with valid JSON, no markdown fences, no extra commentary, in exactly this shape: {\"item_name\": string, \"components\": [{\"part\": string, \"material\": string, \"bin\": \"red\"|\"yellow\"|\"blue\"|\"green\", \"reason\": string}]}" },
        {
          inline_data: {
            mime_type: "image/jpeg",
            data: $json.body.image.replace(/^data:image\/\w+;base64,/, '')
          }
        }
      ]
    }
  ],
  generationConfig: { temperature: 0.2, maxOutputTokens: 500 }
}) }}

parameters.jsCode:
const res = $input.first().json;
let raw = '';
try {
  raw = res.candidates[0].content.parts[0].text;
} catch (e) {
  return [{ json: { item_name: 'Unknown item', components: [], error: 'No response from Gemini' } }];
}
let cleaned = raw.replace(/```json/g, '').replace(/```/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { item_name: 'Unknown item', components: [], error: 'Could not parse model response' };
}
return [{ json: parsed }];
